using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Gestor de Emblemas (Tarefa #32) — verifica automaticamente as condições de
/// obtenção de cada emblema e concede-os (define a sua <see cref="EmblemData.obtainedVariable"/>
/// em GameVariables) quando as condições são cumpridas.
///
/// <b>Condições por tipo de emblema:</b>
/// <list type="bullet">
///   <item><b>Emblemas de Mundo</b> (via <see cref="WorldData.worldEmblem"/>):
///     obtidos ao derrotar o boss do respectivo mundo
///     (<see cref="PlayerProgress.HasDefeatedBoss"/>).</item>
///   <item><b>Boss Alternativo</b>: quando todos os
///     <see cref="worlds"/> têm o seu emblema obtido, define
///     <see cref="allWorldEmblemsVariable"/> = true — o nível usa esta variável
///     para escolher a variante do boss final.</item>
///   <item><b>Emblema de Apolo</b> (<see cref="apoloEmblem"/>): obtido quando
///     qualquer variável de <see cref="apoloTrialCompletedVariables"/> for true
///     (CompletedVariable das ChallengeDefinitions com isApoloTrial).</item>
///   <item><b>Emblema de Gaia</b> (<see cref="gaiaEmblem"/>): obtido quando
///     <see cref="PlayerProgress.GetTotalCompletionPercent"/> ≥ 100.</item>
///   <item><b>Emblema de Zeus</b> (<see cref="zeusEmblem"/>): obtido quando
///     Gaia E Apolo estão ambos obtidos (GDD Tarefa #31: "Gaia + Apolo = 101%
///     e Emblema de Zeus").</item>
/// </list>
///
/// <b>Quando verificar:</b> <see cref="CheckAll"/> é chamado automaticamente após:
/// <list type="bullet">
///   <item><see cref="PlayerProgress.SetBossDefeated"/> (boss derrotado).</item>
///   <item><see cref="ChallengeManager.HandleSuccess"/> (desafio concluído).</item>
///   <item><see cref="PlayerProgress.AnimalUnlocked"/> (último animal libertado).</item>
///   <item><see cref="PlayerProgress.PickupCollected"/> (última Runa, Sussurro, baú, etc.).</item>
///   <item><see cref="MissionManager.OnMissionCompleted"/> (missão concluída).</item>
///   <item><c>OnEnable</c> (ao carregar uma cena/save).</item>
/// </list>
///
/// <b>Notificação:</b> ao conceder um emblema, dispara <see cref="EmblemGranted"/>
/// — ligar para mostrar uma notificação na HUD (ex: "Emblema obtido!").
///
/// <b>Montagem no Editor:</b>
/// - Colocar na cena persistente (DontDestroyOnLoad) ou na cena de gameplay.
/// - Preencher <see cref="gaiaEmblem"/>, <see cref="apoloEmblem"/>,
///   <see cref="zeusEmblem"/>.
/// - Preencher <see cref="worlds"/> com os 6 WorldData (um por mundo).
/// - <see cref="allWorldEmblemsVariable"/>: nome da variável bool em GameVariables
///   que activa o boss alternativo (ex: "Emblemas_TodosOsMundos").
/// - <see cref="apoloTrialCompletedVariables"/>: preencher com o(s)
///   ChallengeDefinition.CompletedVariable das Provações de Apolo.
/// - Preencher <see cref="allAreas"/>, <see cref="allForms"/>,
///   <see cref="allMissions"/>, <see cref="allEmblems"/> (os 9 emblemas) para
///   o cálculo de percentagem do Emblema de Gaia.
/// </summary>
public class EmblemManager : MonoBehaviour
{
    public static EmblemManager Instance { get; private set; }

    // ==================== Emblemas Globais ====================

    [Header("Emblemas Globais")]
    [Tooltip("Emblema de Gaia (EmblemData.isGaiaEmblem = true). Obtido ao atingir 100% de conclusão.")]
    public EmblemData gaiaEmblem;

    [Tooltip("Emblema de Apolo (EmblemData.isApoloEmblem = true). Obtido ao completar qualquer Provação de Apolo listada em 'apoloTrialCompletedVariables'.")]
    public EmblemData apoloEmblem;

    [Tooltip("Emblema de Zeus (EmblemData.isBonus = true). Obtido quando Gaia + Apolo ambos obtidos (GDD: 101%).")]
    public EmblemData zeusEmblem;

    // ==================== Emblemas de Mundo ====================

    [Header("Emblemas de Mundo")]
    [Tooltip("Os 6 WorldData do jogo. O emblema de cada mundo (WorldData.worldEmblem) é obtido ao derrotar o boss desse mundo.")]
    public List<WorldData> worlds = new List<WorldData>();

    [Header("Boss Alternativo")]
    [Tooltip("Variável bool em GameVariables definida como true quando todos os emblemas de mundo estiverem obtidos. O nível do boss final usa esta variável para escolher a variante alternativa.")]
    public string allWorldEmblemsVariable;

    // ==================== Provação de Apolo ====================

    [Header("Provação de Apolo")]
    [Tooltip("Número de Runas de Apolo necessárias para obter o Emblema de Apolo. Padrão: 6 (uma por Provação de Apolo no jogo). O player acumula Runas de Apolo como recompensa de cada Provação concluída; ao atingir este valor, o Emblema é concedido.")]
    [Min(1)] public int runasDeApoloRequired = 6;

    [Tooltip("(Legado/alternativo) ChallengeDefinition.CompletedVariable de desafios marcados como 'isApoloTrial'. Quando qualquer uma destas variáveis for true em GameVariables, o Emblema de Apolo é concedido — condição alternativa à contagem de Runas de Apolo.")]
    public List<string> apoloTrialCompletedVariables = new List<string>();

    // ==================== Área Secreta de Apolo ====================

    [Header("Área Secreta de Apolo (desbloqueada ao obter o Emblema de Apolo)")]
    [Tooltip("AreaData da área secreta desbloqueada automaticamente quando o Emblema de Apolo é concedido (6 Runas de Apolo recolhidas). O WorldMapController.CheckApoloAreaUnlock() detecta esta mudança e reproduz a sequência de câmara. Deixar vazio para desactivar esta funcionalidade.")]
    public AreaData apoloSecretArea;

    // ==================== Listas para Cálculo de % (Emblema de Gaia) ====================

    [Header("Listas para % de Conclusão (Emblema de Gaia)")]
    [Tooltip("Todas as AreaData do jogo — passadas a PlayerProgress.GetTotalCompletionPercent.")]
    public List<AreaData> allAreas = new List<AreaData>();

    [Tooltip("Todas as AnimalFormData do jogo.")]
    public List<AnimalFormData> allForms = new List<AnimalFormData>();

    [Tooltip("Todas as MissionData do jogo.")]
    public List<MissionData> allMissions = new List<MissionData>();

    [Tooltip("Todos os 9 emblemas (6 mundos + Gaia + Apolo + Zeus).")]
    public List<EmblemData> allEmblems = new List<EmblemData>();

    // ==================== Evento ====================

    /// <summary>
    /// Disparado quando um emblema é obtido pela primeira vez.
    /// Parâmetro: o <see cref="EmblemData"/> concedido.
    /// Ligar para mostrar notificação/SFX na HUD.
    /// </summary>
    public static event System.Action<EmblemData> EmblemGranted;

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => EmblemGranted = null;

    // ==================== Singleton ====================

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
        // Não persistir: EmblemManager vive na cena de gameplay (junto com
        // ChallengeManager/MissionManager). Se for necessário torná-lo persistente,
        // adicionar DontDestroyOnLoad (a limpeza de Instance já é feita em OnDestroy).
    }

    private void OnDestroy()
    {
        // Padrão dos outros managers: não deixar a referência estática a
        // apontar para um objecto destruído ao trocar/descarregar a cena.
        if (Instance == this) Instance = null;
    }

    private void OnEnable()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null)
        {
            progress.AnimalUnlocked       += OnProgressEvent;
            progress.PickupCollected      += OnPickupEvent;
            progress.RunasDeApoloChanged  += OnRunasDeApoloChanged;
        }

        MissionManager.OnMissionCompleted += OnMissionCompleted;

        // Verifica ao (re)activar — apanha casos de save carregado ou cena recarregada.
        CheckAll();
    }

    private void OnDisable()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null)
        {
            progress.AnimalUnlocked       -= OnProgressEvent;
            progress.PickupCollected      -= OnPickupEvent;
            progress.RunasDeApoloChanged  -= OnRunasDeApoloChanged;
        }

        MissionManager.OnMissionCompleted -= OnMissionCompleted;
    }

    // Adaptadores de assinatura → CheckAll
    private void OnProgressEvent(string _) => CheckAll();
    private void OnPickupEvent(PickupType _, string __) => CheckAll();
    private void OnMissionCompleted(MissionData _) => CheckAll();
    private void OnRunasDeApoloChanged(int _) => CheckAll();

    // ==================== Verificação Principal ====================

    /// <summary>
    /// Verifica todas as condições de emblema e concede os que ainda não foram
    /// obtidos. Chamar após boss derrotado, desafio concluído, ou save carregado.
    /// Idempotente: seguro chamar várias vezes (só concede se ainda não obtido).
    /// </summary>
    public void CheckAll()
    {
        var vars = GameVariables.Instance;
        var progress = PlayerProgress.Instance;
        if (vars == null || progress == null) return;

        // ---- 1. Emblemas de Mundo ----
        bool allWorldEmblemsObtained = worlds != null && worlds.Count > 0;

        if (worlds != null)
        {
            foreach (var world in worlds)
            {
                if (world?.worldEmblem == null) continue;
                var emblem = world.worldEmblem;
                if (string.IsNullOrEmpty(emblem.obtainedVariable)) continue;

                bool obtained = vars.GetBool(emblem.obtainedVariable);

                if (!obtained && progress.HasDefeatedBoss(world))
                {
                    Grant(emblem, vars);
                    obtained = true;
                }

                if (!obtained) allWorldEmblemsObtained = false;
            }
        }
        else
        {
            allWorldEmblemsObtained = false;
        }

        // ---- 2. Boss Alternativo: todos os emblemas de mundo obtidos ----
        if (!string.IsNullOrEmpty(allWorldEmblemsVariable) && allWorldEmblemsObtained)
        {
            if (!vars.GetBool(allWorldEmblemsVariable))
                vars.SetBool(allWorldEmblemsVariable, true);
        }

        // ---- 3. Emblema de Apolo: 6 Runas de Apolo recolhidas ----
        if (apoloEmblem != null && !string.IsNullOrEmpty(apoloEmblem.obtainedVariable)
            && !vars.GetBool(apoloEmblem.obtainedVariable))
        {
            bool apoloUnlocked = false;

            // Condição primária: Runas de Apolo acumuladas (PlayerProgress.runasDeApolo).
            if (progress.runasDeApolo >= runasDeApoloRequired)
                apoloUnlocked = true;

            // Condição alternativa/legado: qualquer variável de Provação concluída.
            if (!apoloUnlocked && apoloTrialCompletedVariables != null)
            {
                foreach (var v in apoloTrialCompletedVariables)
                {
                    if (!string.IsNullOrEmpty(v) && vars.GetBool(v))
                    {
                        apoloUnlocked = true;
                        break;
                    }
                }
            }

            if (apoloUnlocked) Grant(apoloEmblem, vars);
        }

        // ---- 4. Emblema de Gaia: ≥ 100% de conclusão ----
        if (gaiaEmblem != null && !string.IsNullOrEmpty(gaiaEmblem.obtainedVariable)
            && !vars.GetBool(gaiaEmblem.obtainedVariable))
        {
            int pct = progress.GetTotalCompletionPercent(allAreas, allForms, allMissions, allEmblems);
            if (pct >= 100) Grant(gaiaEmblem, vars);
        }

        // ---- 5. Emblema de Zeus: Gaia + Apolo ambos obtidos ----
        if (zeusEmblem != null && !string.IsNullOrEmpty(zeusEmblem.obtainedVariable)
            && !vars.GetBool(zeusEmblem.obtainedVariable))
        {
            bool gaiaObtained  = gaiaEmblem  != null && !string.IsNullOrEmpty(gaiaEmblem.obtainedVariable)  && vars.GetBool(gaiaEmblem.obtainedVariable);
            bool apoloObtained = apoloEmblem != null && !string.IsNullOrEmpty(apoloEmblem.obtainedVariable) && vars.GetBool(apoloEmblem.obtainedVariable);

            if (gaiaObtained && apoloObtained) Grant(zeusEmblem, vars);
        }
    }

    // ==================== Utilitários ====================

    private void Grant(EmblemData emblem, GameVariables vars)
    {
        vars.SetBool(emblem.obtainedVariable, true);
        EmblemGranted?.Invoke(emblem);
        Debug.Log($"[EmblemManager] Emblema obtido: {emblem.displayName}");

        // Área secreta de Apolo: desbloqueia automaticamente ao obter o Emblema de Apolo.
        if (emblem == apoloEmblem && apoloSecretArea != null)
        {
            var progress = PlayerProgress.Instance;
            if (progress != null && !progress.IsAreaUnlocked(apoloSecretArea))
            {
                progress.UnlockArea(apoloSecretArea);
                Debug.Log($"[EmblemManager] Área secreta de Apolo desbloqueada: {apoloSecretArea.displayName}");
            }
        }
    }
}
